sys_script_include.script:
var AROPCheckSeeder_HS = Class.create();
AROPCheckSeeder_HS.prototype = {
    initialize: function() {},
    getChecks: function() {
        return [{"module":"HS","check_name":"HS Inspection Volume","order":null,"check_script":"(function(){
var ga=new GlideAggregate("sn_hs_rm_inspection");
ga.addAggregate("COUNT");ga.query();
var c=ga.next()?parseInt(ga.getAggregate("COUNT")):0;
if(c>=20)return{status:"ready",actualValue:c+" inspections",finding:c+" inspections found."};
if(c>0)return{status:"needs_attention",actualValue:c+" inspections",finding:c+" inspections found."};
return{status:"needs_attention",actualValue:"0 inspections",finding:"No safety inspections found."};
})()","ai_justification":"Inspection volume reflects operational safety activity that benefits from AI-assisted finding generation and risk scoring. Higher inspection volumes increase the ROI of Now Assist recommendations and automated corrective action creation.","remediation_guidance":"Conduct safety inspections through the HS module.","is_manual":"0","is_clone_sensitive":"0"},{"module":"HS","check_name":"HS Safety Register Volume","order":null,"check_script":"(function(){
var ga=new GlideAggregate("sn_hs_rm_safety_register");
ga.addAggregate("COUNT");ga.query();
var c=ga.next()?parseInt(ga.getAggregate("COUNT")):0;
if(c>=10)return{status:"ready",actualValue:c+" register items",finding:c+" safety register items found."};
if(c>0)return{status:"needs_attention",actualValue:c+" register items",finding:c+" safety register items found."};
return{status:"needs_attention",actualValue:"0 items",finding:"No safety register items found."};
})()","ai_justification":"Safety register records capture ongoing compliance obligations that benefit from AI-assisted monitoring and alert generation. Adequate register volume enables Now Assist to identify compliance gaps and recommend corrective actions proactively.","remediation_guidance":"Populate the safety register with required compliance items.","is_manual":"0","is_clone_sensitive":"0"},{"module":"HS","check_name":"HS Hazard Volume","order":null,"check_script":"(function(){
var ga=new GlideAggregate("sn_hs_rm_hazard");
ga.addAggregate("COUNT");ga.query();
var c=ga.next()?parseInt(ga.getAggregate("COUNT")):0;
if(c>=50)return{status:"ready",actualValue:c+" hazards",finding:c+" hazard records found."};
if(c>0)return{status:"needs_attention",actualValue:c+" hazards",finding:c+" hazard records found."};
return{status:"value_blocker",actualValue:"0 hazards",finding:"No hazard records found."};
})()","ai_justification":"Hazard records represent identified workplace risks that Now Assist can analyze for patterns and recommend controls. Adequate hazard data volume enables AI to surface insights across locations, departments, and hazard categories.","remediation_guidance":"Ensure workplace hazards are logged in the HS module.","is_manual":"0","is_clone_sensitive":"0"},{"module":"HS","check_name":"HS Finding Volume","order":null,"check_script":"(function(){
var ga=new GlideAggregate("sn_hs_rm_finding");
ga.addAggregate("COUNT");ga.query();
var c=ga.next()?parseInt(ga.getAggregate("COUNT")):0;
if(c>=20)return{status:"ready",actualValue:c+" findings",finding:c+" HS findings found."};
if(c>0)return{status:"needs_attention",actualValue:c+" findings",finding:c+" HS findings found."};
return{status:"needs_attention",actualValue:"0 findings",finding:"No HS findings found."};
})()","ai_justification":"HS finding volume reflects the output of inspections and audits that Now Assist can summarize and prioritize. Higher finding volumes increase the value of AI-generated corrective action recommendations and trend analysis.","remediation_guidance":"Ensure inspection and audit findings are captured in the HS module.","is_manual":"0","is_clone_sensitive":"0"},{"module":"HS","check_name":"HS Work Permit Volume","order":null,"check_script":"(function(){
var ga=new GlideAggregate("sn_hs_rm_work_permit");
ga.addAggregate("COUNT");ga.query();
var c=ga.next()?parseInt(ga.getAggregate("COUNT")):0;
if(c>=20)return{status:"ready",actualValue:c+" permits",finding:c+" work permits found."};
if(c>0)return{status:"needs_attention",actualValue:c+" permits",finding:c+" work permits found."};
return{status:"needs_attention",actualValue:"0 permits",finding:"No work permits found."};
})()","ai_justification":"Work permit volume reflects safety-critical activities requiring AI-assisted review and compliance checking. Now Assist can help permit approvers by summarizing requirements and flagging missing conditions before approval.","remediation_guidance":"Ensure work permits are being issued and managed through the HS module.","is_manual":"0","is_clone_sensitive":"0"},{"module":"HS","check_name":"Now Assist for Health & Safety Installed","order":null,"check_script":"(function(){
var sa=new GlideRecord("sys_store_app");
sa.addQuery("scope","sn_hs_gen_ai");
sa.setLimit(1);sa.query();
if(sa.next())return{status:"ready",actualValue:"v"+sa.getValue("version"),finding:"Now Assist for Health & Safety is installed."};
return{status:"value_blocker",actualValue:"Not installed",finding:"Now Assist for Health & Safety (sn_hs_gen_ai) is not installed."};
})()","ai_justification":"Now Assist for Health and Safety enables AI-powered case summarization, incident analysis, and resolution guidance for EHS workflows. Without this plugin, health and safety teams cannot leverage generative AI to accelerate incident resolution and compliance reporting.","remediation_guidance":"Install Now Assist for Health and Safety from the ServiceNow Store.","is_manual":"0","is_clone_sensitive":"0"},{"module":"HS","check_name":"HS Assignment Groups Configured","order":null,"check_script":"(function(){
var ga=new GlideAggregate("sys_user_group");
ga.addQuery("name","CONTAINS","safety");
ga.addAggregate("COUNT");ga.query();
var c=ga.next()?parseInt(ga.getAggregate("COUNT")):0;
if(c>=2)return{status:"ready",actualValue:c+" groups",finding:c+" safety assignment groups found."};
if(c>0)return{status:"needs_attention",actualValue:c+" group",finding:c+" safety group found."};
return{status:"value_blocker",actualValue:"0 groups",finding:"No safety assignment groups found."};
})()","ai_justification":"Properly configured assignment groups ensure that AI Agent task assignments and Now Assist recommendations are routed to the correct safety teams. Without this, automated assignments from AI-generated actions may fail or go unresolved.","remediation_guidance":"Configure HS assignment groups aligned to safety domains and regions.","is_manual":"0","is_clone_sensitive":"0"},{"module":"HS","check_name":"HS Case Volume","order":null,"check_script":"(function(){
var ga=new GlideAggregate("sn_hs_cm_case");
ga.addAggregate("COUNT");ga.query();
var c=ga.next()?parseInt(ga.getAggregate("COUNT")):0;
if(c>=100)return{status:"ready",actualValue:c+" cases",finding:c+" HS cases found."};
if(c>0)return{status:"needs_attention",actualValue:c+" cases",finding:c+" HS cases found. Limited data."};
return{status:"needs_attention",actualValue:"0 cases",finding:"No HS cases found. Module may be newly deployed."};
})()","ai_justification":"HS case volume determines the impact of Now Assist case summarization and AI-assisted resolution. Higher case volumes mean greater time savings for safety managers who benefit most from AI-generated summaries and recommended actions.","remediation_guidance":"Ensure health and safety cases are being submitted through the HS module.","is_manual":"0","is_clone_sensitive":"0"},{"module":"HS","check_name":"HS Audit Volume","order":null,"check_script":"(function(){
var ga=new GlideAggregate("sn_hs_rm_audit");
ga.addAggregate("COUNT");ga.query();
var c=ga.next()?parseInt(ga.getAggregate("COUNT")):0;
if(c>=20)return{status:"ready",actualValue:c+" audits",finding:c+" HS audits found."};
if(c>0)return{status:"needs_attention",actualValue:c+" audits",finding:c+" HS audits found."};
return{status:"needs_attention",actualValue:"0 audits",finding:"No HS audits found."};
})()","ai_justification":"Audit volume indicates the frequency of compliance assessments that can be enhanced with AI-generated findings summaries and corrective action recommendations. Now Assist can accelerate audit closure and improve documentation quality.","remediation_guidance":"Conduct health and safety audits through the HS module.","is_manual":"0","is_clone_sensitive":"0"},{"module":"HS","check_name":"HS Risk Assessment Volume","order":null,"check_script":"(function(){
var ga=new GlideAggregate("sn_hs_rm_risk_assessment");
ga.addAggregate("COUNT");ga.query();
var c=ga.next()?parseInt(ga.getAggregate("COUNT")):0;
if(c>=10)return{status:"ready",actualValue:c+" assessments",finding:c+" HS risk assessments found."};
if(c>0)return{status:"needs_attention",actualValue:c+" assessments",finding:c+" HS risk assessments found."};
return{status:"needs_attention",actualValue:"0 assessments",finding:"No HS risk assessments found."};
})()","ai_justification":"Risk assessment volume indicates the breadth of safety risk management activity. Now Assist can analyze risk descriptions and suggest mitigations, accelerating risk reviews and improving consistency of risk documentation.","remediation_guidance":"Complete risk assessments in the HS module to build AI training signal.","is_manual":"0","is_clone_sensitive":"0"}];
    },
    type: 'AROPCheckSeeder_HS'
};
